  border: 1px solid #87d068;
  background-color: #87d068; }
  .rc-switch-checked .rc-switch-inner {
    left: 6px; }
  .rc-switch-checked:after {
    left: 22px; }

.rc-switch-disabled {
  cursor: no-drop;
  background: #ccc;
  border-color: #ccc; }
  .rc-switch-disabled:after {
    background: #9e9e9e;
    animation-name: none;
    cursor: no-drop; }
  .rc-switch-disabled:hover:after {
    transform: scale(1);
    animation-name: none; }

.rc-switch-label {
  display: inline-block;
  line-height: 20px;
  font-size: 14px;
  padding-left: 10px;
  vertical-align: middle;
  white-space: normal;
  pointer-events: none;
  user-select: text; }

@keyframes rcSwitchOn {
  0% {
    transform: scale(1); }
  50% {
    transform: scale(1.25); }
  100% {
    transform: scale(1.1); } }

@keyframes rcSwitchOff {
  0% {
    transform: scale(1.1); }
  100% {
    transform: scale(1); } }

